# Category: api_gateway_security

from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

@app.route('/api/<path:endpoint>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def api_gateway(endpoint):
    token = request.headers.get('Authorization')
    
    if not token:
        return jsonify({'error': 'Authorization header is missing'}), 401
    
    try:
        # Assuming the token is in the form "Bearer <token>"
        token = token.split()[1]
        user_claims = jwt.decode(token, options={"verify_signature": False})
        
        # Forward the request to the backend service
        # Here you can add the logic to forward the request to the actual backend service
        # For demonstration purposes, we will just return the user claims
        return jsonify({'user_claims': user_claims, 'requested_endpoint': endpoint}), 200
    
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token has expired'}), 401
    except jwt.InvalidTokenError:
        return jsonify({'error': 'Invalid token'}), 401

if __name__ == '__main__':
    app.run(debug=True)